import{_ as a,o as b,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"光明","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/原力/光明.md","filePath":"4.资源分区/6.技艺及称号/能量类/原力/光明.md"}'),p={name:"4.资源分区/6.技艺及称号/能量类/原力/光明.md"};function o(d,e,l,i,_,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"光明",tabindex:"-1"},[n("光明 "),r("a",{class:"header-anchor",href:"#光明","aria-label":'Permalink to "光明"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"汹涌疾风023")])])],-1),s('<h1 id="光明-1" tabindex="-1">光明 <a class="header-anchor" href="#光明-1" aria-label="Permalink to &quot;光明&quot;">​</a></h1><p>光明<br> 这一类原力需要人物具有光明原力才能使用。<br> 本技能树的能量消耗为原力。</p><p>原力安抚<br> 价格：D+500<br> 动作：迅捷<br> 能耗：2<br> 目标：单体<br> 持续：立即<br> 描述：绝地武士使用原力并辅以言语来安抚目标的精神状态。<br> 效果：解除一个触及范围内的单位受到C级别及以下的胁迫、思维控制、支配、混乱效果，其在一轮内进行的意志豁免获得6dp士气加值。<br> 差价升级：C+1000/B+2000/A+4000<br> 能量消耗提升至6/10/14<br> 从C级开始，人物可以反射动作将这一能力对自身使用。<br> 解除的效果等级提升至B/A/S级，意志豁免加值提升至12/24/48点。</p><p>原力恢复<br> 价格：D+500<br> 动作：移动<br> 能耗：2<br> 目标：单体<br> 持续：一轮<br> 描述：绝地武士引导光明原力以治愈目标的伤势，尽管这一能力会相当的消耗绝地武士的精神专注，但他们往往乐此不疲。<br> 效果：使一个触及范围内的单位获得2点快速医疗或者1点异常点数恢复，在使用时选择，二者共用24点医疗点。<br> 使用者可以在能力持续时间内使用花招动作令这一能力的持续时间延长一轮，对同个单位一轮只能延长一次持续时间。若是这一能力作用了多个单位，使用者需要分别使用花招动作来延长持续时间。<br> 此外，使用者还能以一个花招动作切换此能力提供的是快速医疗还是异常点数恢复。<br> 差价升级：C+1000/B+2000/A+4000<br> 能量消耗提升至6/10/14<br> 快速医疗提升至4/8/16；异常点数恢复提升至2/4/8；医疗点提升至72/144/288。</p><p>原力坚盾<br> 价格：B+2000<br> 动作：标准<br> 能耗：10<br> 目标：自身<br> 持续：一场景<br> 效果：在持续时间内视为全防御状态，并将基础防御的防御类型转化为力场防御。同时获得等同感知属性点力场防御与基于力场防御的【超级坚韧】与【适应】。此能力可以一个迅捷动作解除。</p><p>原力守护<br> 价格：C+1000<br> 动作：移动<br> 能耗：6<br> 目标：自身<br> 持续：一轮<br> 效果：进行一次格挡并为触及范围内的友方提供全遮蔽，在持续时间内自身在受到强制性位移效果时，减少沉着附加*5米移动距离。此能力可以一个自由动作解除。<br> 差价升级至B+2000：<br> 能耗提升至10<br> 动作改为迅捷动作<br> 持续时间改为一场景<br> 减少的位移距离提升至沉着附加*10米。</p><p>原力强固<br> 价格：C+1000<br> 动作：移动<br> 能耗：6<br> 目标：自身<br> 持续：一场景<br> 效果：使用原力增强自己的身体素质，在持续时间内，人物获得以下好处：<br> 1、生理属性检定获得沉着附加*2点能量加值<br> 2、移动速度提升30米<br> 3、防御上获得沉着附加*2点洞察加值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(p,[["render",o]]);export{f as __pageData,m as default};
